public class BlueGreenController {

    public enum Slot { BLUE, GREEN }

    private Slot activeSlot = Slot.BLUE;
    private int blueWeight = 100;
    private int greenWeight = 0;

    public void shiftTraffic(int bluePercent, int greenPercent) {
        // Validate total must equal 100
        if (bluePercent + greenPercent != 100) {
            throw new IllegalArgumentException("Traffic weights must sum to 100");
        }
        this.blueWeight = bluePercent;
        this.greenWeight = greenPercent;
    }

    public void promoteGreen() {
        // Make Green the active slot, send all traffic to it
        activeSlot = Slot.GREEN;
        blueWeight = 0;
        greenWeight = 100;
    }

