        // Revert to Blue as active slot with 100% traffic
        // TODO
    }

    public Slot routeRequest(double randomValue) {
        // randomValue is between 0.0 and 1.0
        // Route to BLUE if randomValue < blueWeight/100.0, else GREEN
        return null; // TODO
    }

    public String status() {
        return "Active: " + activeSlot + " | Blue: " + blueWeight + "% | Green: " + greenWeight + "%";
    }

    public static void main(String[] args) {
        BlueGreenController controller = new BlueGreenController();
        System.out.println(controller.status());

        controller.shiftTraffic(80, 20);
