import java.util.*;

public class K8sPodSpecGenerator {

    public record ResourceRequirements(String memoryRequest, String memoryLimit,
                                       String cpuRequest, String cpuLimit) {}

    public record ContainerSpec(
        String name,
        String image,
        int containerPort,
        Map<String, String> envVars,
        ResourceRequirements resources
    ) {}

    public String generate(String podName, String namespace, ContainerSpec container) {
        StringBuilder sb = new StringBuilder();
        sb.append("apiVersion: v1\n");
        sb.append("kind: Pod\n");
        sb.append("metadata:\n");
        sb.append("  name: ").append(podName).append("\n");
        sb.append("  namespace: ").append(namespace).append("\n");
        sb.append("spec:\n");
        sb.append("  containers:\n");
        sb.append("  - name: ").append(container.name()).append("\n");
        sb.append("    image: ").append(container.image()).append("\n");
        sb.append("    ports:\n");
        sb.append("    - containerPort: ").append(container.containerPort()).append("\n");

        // TODO: add env vars section
        // TODO: add resources section with requests and limits

        return sb.toString().trim();
    }

    public static void main(String[] args) {
        K8sPodSpecGenerator gen = new K8sPodSpecGenerator();
        ContainerSpec spec = new ContainerSpec(
            "api",
            "myapp:1.0.0",
            8080,
            Map.of("SPRING_PROFILES_ACTIVE", "production", "LOG_LEVEL", "WARN"),
            new ResourceRequirements("256Mi", "512Mi", "250m", "500m")
        );
        System.out.println(gen.generate("api-pod", "default", spec));
    }
}
